<script setup lang="ts">
  const router = useRouter();
  const storeTag = await useStoreTag();

  let showHidden = $ref(true);
  let newTagName = $ref('');

  async function save() {
    const tag = Tag.fromData({ name: newTagName });
    await storeTag.tagSave(tag);
    newTagName = '';
    return tag;
  }

  function discard() {
    newTagName = '';
  }

  async function saveAndEdit() {
    const tag = await save();
    router.push({ path: `/tag/${tag.id}` });
  }

  const tags = $computed(() =>
    showHidden ? storeTag.tags : storeTag.tagsAvailable,
  );

  const showEye = $computed(
    () => storeTag.tags.length > storeTag.tagsAvailable.length,
  );
</script>

<template>
  <NuxtLayout
    :is-loading="!storeTag.isLoaded"
    name="common"
  >
    <template #default>
      <TransitionFade
        group
        class="px-2 pt-2 flex flex-col gap-2"
      >
        <div
          v-if="!tags.length"
          class="uppercase p-2 flex items-center justify-center"
        >
          <span v-if="!storeTag.tags.length">No tags</span>
          <span v-else>No tags available</span>
        </div>
        <NuxtLink
          v-for="tag in tags"
          :key="tag.id"
          :class="[
            'p-2',
            'rounded',
            'bg-secondary/5',
            !tag.isAvailable && 'text-secondary/50',
          ]"
          :to="`/tag/${tag.id}`"
        >
          <div :class="['flex', 'items-end']">
            {{ tag.name }}
            <div class="flex-grow"></div>
            <Progress
              v-slot="{ total, done }"
              :total="tag.tasksTotal"
              :done="tag.tasksDone"
            >
              {{ done }} / {{ total }} tasks
            </Progress>
          </div>
          <Availability
            :ms-switch-after="tag.tsSwitchAt"
            :is-available="tag.isAvailable"
          />
        </NuxtLink>
      </TransitionFade>
    </template>
    <template #footer>
      <Button
        v-if="newTagName"
        icon="fa6-solid:xmark"
        flat
        @click="discard"
      />
      <Toggle
        v-else-if="showEye"
        v-model="showHidden"
        :class="[showHidden && 'text-primary']"
        flat
      >
        <Icon name="fa6-solid:eye" />
      </Toggle>
      <Input
        v-model="newTagName"
        class="flex-grow"
        placeholder="New tag"
        flat
      />
      <template v-if="newTagName">
        <Button
          flat
          icon="fluent:save-edit-24-filled"
          @click="saveAndEdit"
        />
        <Button
          flat
          icon="fluent:save-24-filled"
          @click="save"
        />
      </template>
    </template>
  </NuxtLayout>
</template>

<style lang="scss"></style>
